{
  static const char hex[] = "0123456789ABCDEF";
  static char       str[BDA_ADDR_STR_LEN + 1];
  char              *pStr = str;

  /* Check for NULL pointer */
  if (pAddr == NULL)
  {
    /* Return string of zeros for NULL input */
    memset(str, '0', BDA_ADDR_STR_LEN);
    str[BDA_ADDR_STR_LEN] = '\0';
    return str;
  }

  /* address is little endian so copy in reverse */
  pAddr += BDA_ADDR_LEN;

  while (pStr < &str[BDA_ADDR_STR_LEN])
  {
    *pStr++ = hex[*--pAddr >> 4];
    *pStr++ = hex[*pAddr & 0x0F];
  }

  /* null terminate string */
  *pStr = 0;

  return str;
}</new_str>

